function start(){new Vue({el:"#app",data:()=>({neck_height:14.5,radius:70.5,top_span:14.885,bottom_span:8,mpx:0,width:470,height:80,growth:1,actived_count:0}),mounted(){addEventListener("mousemove",t=>{const i=this.$refs.stage.getBoundingClientRect();let h=t.clientX-i.x,n=h;n<20&&(n=20),n>this.width-20&&(n=this.width-20),h-i.right>20&&(n=this.width/2),this.mpx=n})},computed:{path(){return calcShape(1*this.width,this.height,1*this.neck_height,1*this.radius,1*this.top_span,1*this.bottom_span)(1*this.mpx,this.growth)},actived_path(){const t=101+76*this.actived_count+20;return calcShape(1*this.width,this.height,1*this.neck_height,1*this.radius,1*this.top_span,1*this.bottom_span)(t,this.growth)}},watch:{actived_count(t){const i=this;i.growth=0;const h={c:0};anime({targets:h,c:1e3,round:1,easing:"cubicBezier(0.25, 0.1, 0.26, 1)",duration:300,update(){i.growth=h.c/1e3}})}}})}function calcShape(t,i,h,n,e,s){return function(a,c=1){const o=n/2,r=a-o,d=a+o,u=h*(1-c);return`\n\t\tM 0 ${h}\n\t\tH ${r}\n\t\tC ${r+s} ${h}, ${a-e} ${u}, ${a} ${u}\n\t\tC ${a+e} ${u}, ${d-s} ${h}, ${d} ${h}\n\t\tH ${t}\n\t\tV ${i}\n\t\tH 0\n\t\tV ${h}\n\t\tZ`}}addEventListener("load",start);